<template>
  <div>
    <self-header
      ref="header"
      :bg_color="header_color"
      :hd_position="header_position"
      :hover_flag="header_hover"
    ></self-header>
    <router-view @headFix="headFix"></router-view>
    <self-footer></self-footer>
    <div class="backtop" @click="backTop" v-show="show_backtop">
      <i class="el-icon-arrow-up"></i>
    </div>
    <!-- <self-loading></self-loading> -->
  </div>
</template>
<script>
import selfHeader from "../components/Header";
import selfFooter from "../components/Footer";
import selfLoading from "../components/loading";

export default {
  components: {
    selfHeader,
    selfFooter,
    selfLoading
  },
  data() {
    return {
      header_title: "", //header 选中标题
      header_color: "", // header背景色
      header_position: "", // header定位
      header_hover: "", // header图标是否显示白光划过效果
      show_backtop: false // 是否显示回到顶部按钮
    };
  },
  beforeRouteUpdate(to, from, next) {
    // 在当前路由改变，但是该组件被复用时调用
    // 举例来说，对于一个带有动态参数的路径 /foo/:id，在 /foo/1 和 /foo/2 之间跳转的时候，
    // 由于会渲染同样的 Foo 组件，因此组件实例会被复用。而这个钩子就会在这个情况下被调用。
    // 可以访问组件实例 `this`
    let title = to.meta.nav;
    if (title) {
      this.$refs.header.selected(title);
    }
    next();
  },
  mounted() {
    window.addEventListener("scroll", this.handleScroll);
  },
  methods: {
    handleScroll() {
      if (this.header_position == "relative") {
        return;
      }
      let scrollTop =
        window.pageYOffset ||
        document.documentElement.scrollTop ||
        document.body.scrollTop;
      if (scrollTop === 0) this.header_color = "transparent";
      if (scrollTop > 100) this.header_color = "rgba(3,3,3,.8)";
      if (scrollTop > 200) this.show_backtop = true;
      if (scrollTop < 200) this.show_backtop = false;
    },
    backTop() {
      // 让回到顶部更加平滑
      let scrollTop;
      var time = setInterval(() => {
        scrollTop =
          window.pageYOffset ||
          document.documentElement.scrollTop ||
          document.body.scrollTop;
        window.scroll(0, scrollTop - 50);
        if (scrollTop === 0) clearInterval(time);
      }, 10);
    },
    headFix(val) {
      this.header_position = val[0];
      this.header_hover = val[1];
      let color = val[2];
      if (color) {
        this.header_color = color;
      }
    }
  }
};
</script>
<style lang="scss">
ul {
  list-style: none;
}
a {
  color: #13497f;
  text-decoration: none;
}

// a:visited {
//   text-decoration: none;
// }
// a:hover {
//   color: red;
//   text-decoration: none;
// }
// a:active {
//   color: red;
//   text-decoration: none;
// }

.backtop {
  width: 60px;
  height: 25px;
  background-color: rgb(255, 135, 36);
  text-align: center;
  position: fixed;
  z-index: 999;
  right: 5%;
  bottom: 0;
  cursor: pointer;
  transition: transform 0.3s;
  animation: rotateIn 0.8s;
  &:hover {
    transform: scale(1.2);
  }
  i {
    color: #ffffff;
    font-size: 30px;
  }
}
</style>



